var lifiRouter = new Hono2();
lifiRouter.get("/quote", async (c) => {
  const parsed = quoteQuerySchema.safeParse(c.req.query());
  if (!parsed.success) {
    return c.json({ error: "Invalid quote query", issues: parsed.error.flatten() }, 400);
  }
  const q = parsed.data;
  const url3 = new URL(LIFI_QUOTE);
  url3.searchParams.set("integrator", process.env.LIFI_INTEGRATOR ?? "oishi");
  url3.searchParams.set("fromChain", q.fromChain);
  url3.searchParams.set("toChain", q.toChain);
  url3.searchParams.set("fromToken", q.fromToken);
  url3.searchParams.set("toToken", q.toToken);
  url3.searchParams.set("fromAmount", q.fromAmount);
  url3.searchParams.set("order", q.order ?? "CHEAPEST");
  if (q.fromAddress?.trim()) url3.searchParams.set("fromAddress", q.fromAddress.trim());
  if (q.toAddress?.trim()) url3.searchParams.set("toAddress", q.toAddress.trim());
  const headers = { Accept: "application/json" };
  const key2 = process.env.LIFI_API_KEY;
  if (key2) headers["x-lifi-api-key"] = key2;
  const res = await fetch(url3.toString(), { headers });
  const bodyText = await res.text();
  try {
    const json3 = JSON.parse(bodyText);
    return Response.json(json3, { status: res.status });
  } catch {
    const status = res.status >= 400 ? res.status : 502;
    return new Response(bodyText || "upstream error", { status });
  }
});

