var import_web36 = require("@solana/web3.js");
var onchainRouter = new Hono2();
onchainRouter.post("/register-agent/:id", requireAuth(), async (c) => {
  const wallet = c.get("wallet");
  const id = c.req.param("id");
  const agent = getAgent(id);
  if (!agent) return c.json({ error: "Agent not found" }, 404);
  if (agent.owner !== wallet) return c.json({ error: "Not your agent" }, 403);
  try {
    const owner = new import_web36.PublicKey(wallet);
    const strategyMask = buildStrategyMask([agent.strategyId]);
    const { transaction, pda } = await buildRegisterAgentTx({
      owner,
      handle: agent.handle.replace("@", ""),
      // strip @ for PDA seed
      displayName: agent.displayName,
      strategyMask,
      rules: { common: agent.commonRules, specific: agent.specificRules }
    });
    return c.json({
      transaction,
      pda,
      handle: agent.handle,
      programId: "EdsJZDNVQ2ncXrXaTFd2aZFhrYqLBJGJBq6xAY26PR9a",
      instructions: "Frontend: deserialize tx \u2192 sign with wallet \u2192 send to Solana devnet",
      estimatedFee: "~0.003 SOL"
    });
  } catch (err2) {
    return c.json({ error: `Failed to build transaction: ${String(err2)}` }, 500);
  }
});
onchainRouter.post("/fund-agent/:id", requireAuth(), async (c) => {
  const wallet = c.get("wallet");
  const id = c.req.param("id");
  const agent = getAgent(id);
  if (!agent) return c.json({ error: "Agent not found" }, 404);
  if (agent.owner !== wallet) return c.json({ error: "Not your agent" }, 403);
  const body = await c.req.json();
  const amountSol = parseFloat(body.amountSol);
  if (!amountSol || amountSol <= 0 || amountSol > 1e3) {
    return c.json({ error: "Amount must be between 0.001 and 1000 SOL" }, 400);
  }
  try {
    const { Connection: Connection4, Transaction, SystemProgram: SystemProgram2, LAMPORTS_PER_SOL } = await import("@solana/web3.js");
    const rpc = process.env.SOLANA_RPC_URL ?? "https://api.devnet.solana.com";
    const connection = new Connection4(rpc, "confirmed");
    const from = new import_web36.PublicKey(wallet);
    const to = new import_web36.PublicKey(agent.walletPublicKey);
    const lamports = Math.floor(amountSol * LAMPORTS_PER_SOL);
    const tx = new Transaction().add(
      SystemProgram2.transfer({ fromPubkey: from, toPubkey: to, lamports })
    );
    tx.recentBlockhash = (await connection.getLatestBlockhash()).blockhash;
    tx.feePayer = from;
    return c.json({
      transaction: tx.serialize({ requireAllSignatures: false }).toString("base64"),
      from: wallet,
      to: agent.walletPublicKey,
      amountSol,
      lamports,
      estimatedFee: "~0.000005 SOL"
    });
  } catch (err2) {
    return c.json({ error: String(err2) }, 500);
  }
});

